import{c as s,cG as i,cb as a,c8 as n,cf as t,cT as l,ce as e}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"07. Load 与 Store 指令","description":"","frontmatter":{"title":"07. Load 与 Store 指令","outline":"deep","layout":"doc","prev":{"text":"06. 立即数操作与移位","link":"/lang/assembly/06_immediates_shifts"},"next":{"text":"08. 分支与跳转","link":"/lang/assembly/08_branches_jumps"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/07_load_store.md","filePath":"lang/assembly/07_load_store.md","lastUpdated":1780201037000}'),p={id:"frontmatter-title",tabindex:"-1"};const d=s({name:"lang/assembly/07_load_store.md"},[["render",function(s,h,d,k,r,o){return i(),a("div",null,[n("h1",p,[t(l(s.$frontmatter.title)+" ",1),h[0]||(h[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=e('<p>Load 和 Store 是 RISC-V 仅有的两条&quot;触摸内存&quot;的桥梁。ALU 操作的对象必须是寄存器——数据必须先 <code>ld</code> 到寄存器、计算、再 <code>sd</code> 回内存。这是 Load-Store 架构的核心纪律：从 RISC-V 汇编程序的视角看，内存是一个可读可写的字节数组，只有 Load 和 Store 能访问它。</p><h2 id="load-指令族" tabindex="-1">Load 指令族 <a class="header-anchor" href="#load-指令族" aria-label="Permalink to “Load 指令族”">​</a></h2><p>Load 指令族使用 I-type 格式，opcode = <code>0000011</code>。funct3 决定数据宽度和扩展方式。</p><p><strong>RV64I Load 指令完整列表</strong>：</p><table tabindex="0"><thead><tr><th>指令</th><th>funct3</th><th>功能</th><th>符号/零扩展</th></tr></thead><tbody><tr><td><code>lb rd, offset(rs1)</code></td><td>000</td><td>读 1 字节 (byte)</td><td>符号扩展至 64 位</td></tr><tr><td><code>lh rd, offset(rs1)</code></td><td>001</td><td>读 2 字节 (halfword)</td><td>符号扩展至 64 位</td></tr><tr><td><code>lw rd, offset(rs1)</code></td><td>010</td><td>读 4 字节 (word)</td><td>符号扩展至 64 位</td></tr><tr><td><code>ld rd, offset(rs1)</code></td><td>011</td><td>读 8 字节 (doubleword)</td><td>无扩展（已是 64 位满宽度）</td></tr><tr><td><code>lbu rd, offset(rs1)</code></td><td>100</td><td>读 1 字节，无符号</td><td>零扩展至 64 位</td></tr><tr><td><code>lhu rd, offset(rs1)</code></td><td>101</td><td>读 2 字节，无符号</td><td>零扩展至 64 位</td></tr><tr><td><code>lwu rd, offset(rs1)</code></td><td>110</td><td>读 4 字节，无符号</td><td>零扩展至 64 位</td></tr></tbody></table><p><strong>命名约定</strong>：<code>l</code> = load，后缀字母表示宽度：<code>b</code>=byte(8b), <code>h</code>=halfword(16b), <code>w</code>=word(32b), <code>d</code>=doubleword(64b)。中间有 <code>u</code> 表示 unsigned（零扩展），无 <code>u</code> 表示 signed（符号扩展）。</p><h3 id="为什么没有-无符号-ld" tabindex="-1">为什么没有&quot;无符号 ld&quot; <a class="header-anchor" href="#为什么没有-无符号-ld" aria-label="Permalink to “为什么没有&quot;无符号 ld&quot;”">​</a></h3><p><code>ld</code> 读 8 字节（64 位）到 64 位寄存器——位宽恰好匹配，不存在扩展问题。任何 64 位位模式在寄存器中如何解释（有符号/无符号）取决于后续使用它的指令（<code>slt</code> vs <code>sltu</code>，<code>srai</code> vs <code>srli</code>），而不是 Load 本身。因此 <code>ldu</code> 不存在——也不需要存在。</p><h3 id="符号扩展-vs-零扩展-选错指令的-bug" tabindex="-1">符号扩展 vs 零扩展：选错指令的 bug <a class="header-anchor" href="#符号扩展-vs-零扩展-选错指令的-bug" aria-label="Permalink to “符号扩展 vs 零扩展：选错指令的 bug”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 内存 0x1000 处有一个字节 0xFE</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x1000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lb   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 0xFFFF_FFFF_FFFF_FFFE（符号扩展，值 = -2）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lbu  t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = 0x0000_0000_0000_00FE（零扩展，值 = 254）</span></span></code></pre></div><p>同一个内存字节，<code>lb</code> 和 <code>lbu</code> 读到寄存器中的值完全不同。这不是 RISC-V 的独特设计——x86 的 <code>movsx</code>/<code>movzx</code> 系列、ARM 的 <code>ldrsb</code>/<code>ldrb</code> 系列都有同样区分。选错指令是汇编中最常见的静默 bug：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 典型错误：用 lb 读取无符号数组元素</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># char buf[256] → 如果用 lb 读，buf[128] 及以上（byte 值 0x80-0xFF）被符号扩展为负数</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正确的做法是 lbu</span></span></code></pre></div><h3 id="load-的寻址方式" tabindex="-1">Load 的寻址方式 <a class="header-anchor" href="#load-的寻址方式" aria-label="Permalink to “Load 的寻址方式”">​</a></h3><p>RISC-V 的寻址只有一种模式：<strong>基址 + 偏移</strong>（base + displacement）。<code>offset</code> 是 12 位有符号立即数，范围 [-2048, 2047]：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t1)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = mem[t1 + 0]（偏移为 0）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t1)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = mem[t1 + 8]（向前偏移 8 字节）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld  t0, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t1)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = mem[t1 - 8]（向后偏移 8 字节）</span></span></code></pre></div><p><code>0(t1)</code> 中偏移为 0 的模式非常常见——当基址寄存器已经指向目标地址时，偏移就是 0。</p><p><strong>为什么只有一种寻址模式？</strong> x86 有基址+索引*比例+偏移的复杂寻址（如 <code>mov rax, [rbx + rcx*8 + 0x100]</code>），一条指令完成地址计算。RISC-V 选择分离：先手动计算地址到寄存器，再 <code>ld</code>。代价是多一条指令，收益是：译码器简单、地址计算延迟可预测、无超标量调度冲突。RISC 哲学再次体现——用简单指令的组合换取可预测的执行。</p><h2 id="store-指令族" tabindex="-1">Store 指令族 <a class="header-anchor" href="#store-指令族" aria-label="Permalink to “Store 指令族”">​</a></h2><p>Store 指令使用独立的 <strong>S-type</strong> 格式，opcode = <code>0100011</code>。</p><p><strong>RV64I Store 指令完整列表</strong>：</p><table tabindex="0"><thead><tr><th>指令</th><th>funct3</th><th>功能</th></tr></thead><tbody><tr><td><code>sb rs2, offset(rs1)</code></td><td>000</td><td>写低 1 字节 (byte)</td></tr><tr><td><code>sh rs2, offset(rs1)</code></td><td>001</td><td>写低 2 字节 (halfword)</td></tr><tr><td><code>sw rs2, offset(rs1)</code></td><td>010</td><td>写低 4 字节 (word)</td></tr><tr><td><code>sd rs2, offset(rs1)</code></td><td>011</td><td>写 8 字节 (doubleword)</td></tr></tbody></table><p>Store 指令<strong>没有符号/无符号之分</strong>。原因很简单：存到内存的是寄存器中原始的位模式——存什么 pattern 就是什么 pattern。&quot;有符号&quot;或&quot;无符号&quot;是 CPU 算出来的，存回内存时只有位模式这一个事实。<code>sb</code> 把 rs2 的低 8 位写入内存，至于这 8 位代表 -128 还是 255，是后续 Load 该关心的事。</p><h3 id="s-type-格式的立即数拆分" tabindex="-1">S-type 格式的立即数拆分 <a class="header-anchor" href="#s-type-格式的立即数拆分" aria-label="Permalink to “S-type 格式的立即数拆分”">​</a></h3><p>S-type 与 I-type 最大的不同在于立即数字段的排列方式：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>S-type: ┌───────┬───────┬───────┬─────┬───────┬─────────┐</span></span>\n<span class="line"><span>        │imm[11:5]│ rs2  │ rs1  │funct3│imm[4:0]│ opcode  │</span></span>\n<span class="line"><span>        └───7────┴───5───┴───5───┴──3───┴───5────┴────7────┘</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>I-type: ┌────────────────────┬───────┬─────┬───────┬─────────┐</span></span>\n<span class="line"><span>        │    imm[11:0]       │ rs1  │funct3│  rd   │ opcode  │</span></span>\n<span class="line"><span>        └─────────12─────────┴───5───┴──3───┴───5───┴────7────┘</span></span></code></pre></div><p>立即数被拆成 <code>imm[11:5]</code>（高 7 位，放在 bit 31:25）和 <code>imm[4:0]</code>（低 5 位，放在 bit 11:7）两部分。为什么不用整齐的 12 位连续排列？观察关键字段的位置：</p><table tabindex="0"><thead><tr><th>字段</th><th>R-type</th><th>I-type</th><th>S-type</th></tr></thead><tbody><tr><td>opcode</td><td>[6:0]</td><td>[6:0]</td><td>[6:0]</td></tr><tr><td>rd</td><td>[11:7]</td><td>[11:7]</td><td>—（无 rd）</td></tr><tr><td>funct3</td><td>[14:12]</td><td>[14:12]</td><td>[14:12]</td></tr><tr><td>rs1</td><td>[19:15]</td><td>[19:15]</td><td>[19:15]</td></tr><tr><td>rs2</td><td>[24:20]</td><td>—（立即数）</td><td>[24:20]</td></tr></tbody></table><p>在三种格式中，<strong>opcode、rs1、rs2、funct3 的位置完全相同</strong>。译码器在确定具体指令之前就可以并行读出这些字段，立即开始寄存器文件的读取。S-type 将立即数拆开填到&quot;冗余&quot;的位置（R-type 的 rd 位 + funct7 位），以保持字段对齐——这不是设计缺陷，而是硬件译码器的刻意优化。</p><h2 id="寻址模式" tabindex="-1">寻址模式 <a class="header-anchor" href="#寻址模式" aria-label="Permalink to “寻址模式”">​</a></h2><p>RISC-V 只有一种寻址模式：<strong>基址 + 偏移</strong>。这是 Load-Store 架构中最简洁的选择——x86 那种&quot;一条指令做太多事&quot;的风格在 RISC 中不存在。</p><h3 id="数组访问" tabindex="-1">数组访问 <a class="header-anchor" href="#数组访问" aria-label="Permalink to “数组访问”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># int64_t array[100] 的遍历</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 数组基地址, a1 = 元素数量</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # i = 0（循环索引）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t1, a0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = &amp;array[0]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">loop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bge  t0, a1, done       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # if i &gt;= n → 结束</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t1)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = array[i]——当前元素值</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 对 t2 做运算 ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 指针前进 8 字节（sizeof(int64_t)）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # i++</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">loop</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">done:</span></span></code></pre></div><p>这里演示了指针算术和索引计数的双重迭代。指针 <code>t1</code> 每次 +8（元素大小），同时 <code>t0</code> 计数循环次数。两种方式等价，选择取决于上下文——指针方式避免乘法；索引+乘法方式当数组不是连续访问时更灵活。</p><h3 id="栈帧访问" tabindex="-1">栈帧访问 <a class="header-anchor" href="#栈帧访问" aria-label="Permalink to “栈帧访问”">​</a></h3><p>栈在 RISC-V ABI 中由 <code>sp</code>（x2）指向。局部变量通常通过 <code>sp</code> 的偏移访问：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 函数序言：分配 32 字节栈帧</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 栈向下增长 32 字节</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 访问栈上的局部变量</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sd   s0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保存 s0 到栈偏移 24 处</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld   s0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 从栈偏移 24 处恢复 s0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 存储局部变量</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sd   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 局部 var1 在 sp+16</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sd   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 局部 var2 在 sp+8</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 函数尾声：回收栈帧</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 栈指针恢复</span></span></code></pre></div><p><code>sd s0, 24(sp)</code> 表示：取寄存器 s0 的 64 位值，写入内存地址 <code>sp + 24</code>。栈帧中的每个变量获得一个固定的 <code>sp + offset</code> 地址——汇编器不帮你记忆变量名字，你需要自行管理偏移量的分配。</p><h3 id="遍历字符串-lb-的典型场景" tabindex="-1">遍历字符串（lb 的典型场景） <a class="header-anchor" href="#遍历字符串-lb-的典型场景" aria-label="Permalink to “遍历字符串（lb 的典型场景）”">​</a></h3><p>字符串在 C/Rust 中是 <code>char</code> 数组（每字符 1 字节），遍历时需要 <code>lbu</code>（无符号 byte load）逐个读取：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 计算以空字符结尾的字符串长度（strlen）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 字符串首地址，返回值在 t0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # len = 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t1, a0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 当前指针</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strlen_loop:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lbu  t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t1)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = *t1（读一个字节，零扩展）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beqz t2, strlen_done    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 遇到 &#39;\\0&#39;（值为 0）→ 结束</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 指针++</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # len++</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    strlen_loop</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strlen_done:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # t0 = 字符串长度</span></span></code></pre></div><p>使用 <code>lbu</code> 而非 <code>lb</code> 的原因：<code>char</code> 在 C 中何时有符号/无符号由实现决定。如果字符串包含高位为 1 的字节（如 UTF-8 编码的中文字符），<code>lb</code> 会将其符号扩展为负数，导致比较 <code>beqz</code> 前的扩展行为。虽然空字符 0x00 不受符号扩展影响（扩展后还是 0），但为确保正确处理无符号字符值，<code>lbu</code> 是正确的选择。</p><h2 id="load-与-store-的协同模式" tabindex="-1">Load 与 Store 的协同模式 <a class="header-anchor" href="#load-与-store-的协同模式" aria-label="Permalink to “Load 与 Store 的协同模式”">​</a></h2><h3 id="读-→-改-→-写-rmw-模式" tabindex="-1">读 → 改 → 写（RMW 模式） <a class="header-anchor" href="#读-→-改-→-写-rmw-模式" aria-label="Permalink to “读 → 改 → 写（RMW 模式）”">​</a></h3><p>内存中变量的增量操作经典的三步走：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># counter++（内存中的 64 位计数器）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># t0 = 计数器内存地址</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 1. 从内存加载</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 2. 寄存器中增量</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sd   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 3. 存回内存</span></span></code></pre></div><p>这是非原子操作——两条指令之间有中断/线程切换的风险。RISC-V A 扩展（原子操作）提供 <code>amoadd.d</code> 等指令来原子化 RMW。但在单线程或无竞争的场景下，load-add-store 就是内存变量的标准操作。</p><h3 id="不同宽度的-load-store-组合" tabindex="-1">不同宽度的 Load/Store 组合 <a class="header-anchor" href="#不同宽度的-load-store-组合" aria-label="Permalink to “不同宽度的 Load/Store 组合”">​</a></h3><p>读取窄数据 → 在 64 位寄存器中处理 → 存回窄宽度：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 将数组中的每个字节加 1（模拟 toupper 风格操作）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 数组基地址, a1 = 长度</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # i = 0</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">byte_loop:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bge  t2, a1, byte_done</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t3, a0, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = &amp;array[i]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lbu  t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t3)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t4 = array[i]（零扩展至 64 位）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t4, t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t4 = t4 + 1（运算在 64 位寄存器中完成）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sb   t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t3)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 只存回低 8 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t2, t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    byte_loop</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">byte_done:</span></span></code></pre></div><p><code>lbu</code> 将字节值零扩展至 64 位，加法在 64 位 ALU 中进行，<code>sb</code> 只将低 8 位写入内存。超过 255 的值用 <code>sb</code> 存储时高位被截断——如果需要饱和加法（&gt;255 时钳位到 255），需额外判断。</p><h3 id="数据块的复制" tabindex="-1">数据块的复制 <a class="header-anchor" href="#数据块的复制" aria-label="Permalink to “数据块的复制”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># memcpy(dest, src, n)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 目标地址, a1 = 源地址, a2 = 字节数</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, a0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保存 dest 原始值（用于返回）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 先按 8 字节块复制</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    srli t1, a2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t1 = n / 8（8 字节块数）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beqz t1, copy_tail      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 不足 8 字节直接跳尾部</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">copy_8:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a1)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 读 8 字节</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 写 8 字节</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi a0, a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi a1, a1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t1, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez t1, copy_8</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">copy_tail:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 处理剩余不足 8 字节的部分（逐字节复制）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    andi t1, a2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x7</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # t1 = n % 8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beqz t1, copy_done</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">copy_byte:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lbu  t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a1)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sb   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a0)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi a0, a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi a1, a1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t1, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez t1, copy_byte</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">copy_done:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   a0, t0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 返回 dest 原始指针</span></span></code></pre></div><p>实际 <code>memcpy</code> 实现会进一步使用更大的块、对齐检查、甚至向量指令。但上述代码展示了 Load/Store 的核心模式：按不同宽度分段处理以最大化吞吐量。</p><h2 id="端序与-load-store-的实际表现" tabindex="-1">端序与 Load/Store 的实际表现 <a class="header-anchor" href="#端序与-load-store-的实际表现" aria-label="Permalink to “端序与 Load/Store 的实际表现”">​</a></h2><p>RISC-V 默认小端序。<code>sd</code> 将 64 位寄存器的字节 0（最低有效字节）存到最低地址，字节 7（最高有效字节）存到最高地址：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 观察小端序存储</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x1000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 基地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x0102030405060708</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 测试值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 存入内存</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 逐字节读回验证端序</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lb   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = 0x08（LSB 在最低地址）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lb   t3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = 0x07</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lb   t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t4 = 0x06</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lb   t5, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t5 = 0x01（MSB 在最高地址）</span></span></code></pre></div><p><code>lb</code> 有符号扩展，读回的值可能是负数——如果字节最高位为 1。用 <code>lbu</code> 可以得到 0-255 的无符号 val。</p><p><strong>跨端序系统通信</strong>：如果你的 RISC-V 代码需要与大端序设备或网络协议交互，必须在 Load 后/Store 前做字节序转换。Linux 内核提供了 <code>cpu_to_be64</code>/<code>be64_to_cpu</code> 等宏，其底层就是字节交换指令（RV32 的 Zbb 扩展有 <code>rev8</code> 字节反转指令，RV64 也有对等变体）。</p><h2 id="对齐要求" tabindex="-1">对齐要求 <a class="header-anchor" href="#对齐要求" aria-label="Permalink to “对齐要求”">​</a></h2><p>RISC-V 规范对 Load/Store 指令的地址对齐有要求。理论上：</p><ul><li><code>ld</code>/<code>sd</code> 需要 8 字节对齐（地址 mod 8 == 0）</li><li><code>lw</code>/<code>sw</code> 需要 4 字节对齐</li><li><code>lh</code>/<code>sh</code> 需要 2 字节对齐</li><li><code>lb</code>/<code>sb</code> 无对齐要求（始终合法）</li></ul><p>但是，RISC-V 规范<strong>允许</strong>实现支持硬件非对齐访问。Linux-capable RISC-V 处理器通常支持非对齐的 <code>ld</code>/<code>sd</code>——但会付出性能代价（可能需要两次内存访问 + 拼接）。对于汇编程序员，除非确实需要处理非对齐数据（如解析网络包），否则始终保持数据自然对齐是最佳实践。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>Load 指令族（opcode=0000011）按宽度分为 ld/lw/lh/lb，带 <code>u</code> 后缀的做零扩展、不带 <code>u</code> 的做符号扩展——选错扩展方式是常见 bug</li><li>Store 指令族（opcode=0100011）无符号/无符号之分——存储的是寄存器中原始位模式</li><li>RISC-V 只有基址+偏移一种寻址模式，简洁统一；数组、栈帧、字符串遍历均基于此</li><li>S-type 的立即数拆分为 imm[11:5] 和 imm[4:0] 是为了保持 rs1/rs2/funct3 字段在 R/I/S 三种格式中位置一致，简化译码器硬件</li><li>RISC-V 默认小端序，低字节在低地址；非对齐访问允许但可能损失性能</li></ul>',64))])}]]);export{h as __pageData,d as default};
